import{_ as a,o as e,c as d,ae as r}from"./chunks/framework.CC-i3qbO.js";const T=JSON.parse('{"title":"Q7: 分布式事务如何解决？Seata的AT模式？","description":"","frontmatter":{},"headers":[],"relativePath":"02-microservice/q7-seata.md","filePath":"02-microservice/q7-seata.md"}'),o={name:"02-microservice/q7-seata.md"};function i(l,t,n,s,h,c){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="q7-分布式事务如何解决-seata的at模式" tabindex="-1">Q7: 分布式事务如何解决？Seata的AT模式？ <a class="header-anchor" href="#q7-分布式事务如何解决-seata的at模式" aria-label="Permalink to &quot;Q7: 分布式事务如何解决？Seata的AT模式？&quot;">​</a></h1><h2 id="分布式事务解决方案" tabindex="-1">分布式事务解决方案 <a class="header-anchor" href="#分布式事务解决方案" aria-label="Permalink to &quot;分布式事务解决方案&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>原理</th><th>优点</th><th>缺点</th><th>适用场景</th></tr></thead><tbody><tr><td>2PC</td><td>两阶段提交</td><td>强一致</td><td>同步阻塞、单点故障</td><td>强一致性要求</td></tr><tr><td>TCC</td><td>Try-Confirm-Cancel</td><td>性能好</td><td>侵入性强</td><td>高性能、业务可控</td></tr><tr><td>可靠消息</td><td>MQ事务消息</td><td>最终一致</td><td>有延迟</td><td>异步场景</td></tr><tr><td>Saga</td><td>正向逆向补偿</td><td>长事务</td><td>可能数据不一致</td><td>长流程</td></tr><tr><td>AT模式</td><td>自动生成反向SQL</td><td>无侵入</td><td>性能损耗</td><td>大多数场景</td></tr></tbody></table><h2 id="seata-at模式原理" tabindex="-1">Seata AT模式原理 <a class="header-anchor" href="#seata-at模式原理" aria-label="Permalink to &quot;Seata AT模式原理&quot;">​</a></h2><h3 id="三种角色" tabindex="-1">三种角色 <a class="header-anchor" href="#三种角色" aria-label="Permalink to &quot;三种角色&quot;">​</a></h3><ul><li><strong>TM（Transaction Manager）</strong>：事务管理器，开启全局事务</li><li><strong>TC（Transaction Coordinator）</strong>：事务协调者，协调各分支事务</li><li><strong>RM（Resource Manager）</strong>：资源管理器，执行SQL、注册分支事务</li></ul><h3 id="执行流程" tabindex="-1">执行流程 <a class="header-anchor" href="#执行流程" aria-label="Permalink to &quot;执行流程&quot;">​</a></h3><ol><li>TM向TC申请开启全局事务，生成XID（全局事务ID）</li><li>各RM执行SQL：记录前后镜像、生成undo_log、注册分支事务、提交本地事务</li><li>RM向TC报告分支事务状态</li><li>如果全部成功：TC发送分支提交，RM异步删除undo_log</li><li>如果失败：TC发送分支回滚，RM根据undo_log生成反向SQL执行</li></ol><h3 id="at模式优点" tabindex="-1">AT模式优点 <a class="header-anchor" href="#at模式优点" aria-label="Permalink to &quot;AT模式优点&quot;">​</a></h3><ul><li><strong>无侵入</strong>：自动生成反向SQL，业务代码无需修改</li><li><strong>性能好</strong>：本地事务一阶段提交</li><li><strong>易用</strong>：配置简单，接入成本低</li></ul>',10)])])}const _=a(o,[["render",i]]);export{T as __pageData,_ as default};
